    def _generate_agent_config(
        self,
        context: Dict[str, Any],
        queries: List[Dict[str, str]]
    ) -> Dict[str, Any]:
        """Generate agent configuration"""
        return {
            "name": f"{context.get('company_name', 'Company')} {context.get('department', 'Team')} Assistant",
            "instructions": f"You help {context.get('department', 'the team')} with {', '.join(context.get('use_cases', ['analytics']))}",
            "tools": [
                {
                    "name": q["name"].lower().replace(" ", "_"),
                    "query": q["esql"]
                }
                for q in queries[:5]
            ]
        }